  'pt': { text: "\ud83e\udd16 Ol\u00e1! Sou seu bot tutor de idiomas pessoal.\n\nVou te ajudar a aprender um novo idioma passo a passo \u2014 atrav\u00e9s de conversa\u00e7\u00e3o, gram\u00e1tica e vocabul\u00e1rio.", greeting: "Ol\u00e1" },
  'fr': { text: "\ud83e\udd16 Bonjour ! Je suis votre bot tuteur de langues personnel.\n\nJe vous aiderai \u00e0 apprendre une nouvelle langue \u00e9tape par \u00e9tape \u2014 \u00e0 travers la conversation, la grammaire et le vocabulaire.", greeting: "Bonjour" },
  'de': { text: "\ud83e\udd16 Hallo! Ich bin dein pers\u00f6nlicher Sprach-Tutor-Bot.\n\nIch helfe dir, eine neue Sprache Schritt f\u00fcr Schritt zu lernen \u2014 durch Gespr\u00e4che, Grammatik und Vokabular.", greeting: "Hallo" },
  'hi': { text: "\ud83e\udd16 \u0928\u092e\u0938\u094d\u0924\u0947! \u092e\u0948\u0902 \u0906\u092a\u0915\u093e \u0935\u094d\u092f\u0915\u094d\u0924\u093f\u0917\u0924 \u092d\u093e\u0937\u093e \u091f\u094d\u092f\u0942\u091f\u0930 \u092c\u0949\u091f \u0939\u0942\u0902\u0964\n\n\u092e\u0948\u0902 \u0906\u092a\u0915\u094b \u0915\u0926\u092e \u0926\u0930 \u0915\u0926\u092e \u090f\u0915 \u0928\u0908 \u092d\u093e\u0937\u093e \u0938\u0940\u0916\u0928\u0947 \u092e\u0947\u0902 \u092e\u0926\u0926 \u0915\u0930\u0942\u0902\u0917\u093e\u0964", greeting: "\u0928\u092e\u0938\u094d\u0924\u0947" },
  'ja': { text: "\ud83e\udd16 \u3053\u3093\u306b\u3061\u306f\uff01\u79c1\u306f\u3042\u306a\u305f\u306e\u500b\u4eba\u8a9e\u5b66\u30c1\u30e5\u30fc\u30bf\u30fc\u30dc\u30c3\u30c8\u3067\u3059\u3002\n\n\u4f1a\u8a71\u3001\u6587\u6cd5\u3001\u8a9e\u5f59\u3092\u901a\u3057\u3066\u3001\u65b0\u3057\u3044\u8a00\u8a9e\u3092\u4e00\u6b69\u4e00\u6b69\u5b66\u3076\u304a\u624b\u4f1d\u3044\u3092\u3057\u307e\u3059\u3002", greeting: "\u3053\u3093\u306b\u3061\u306f" },
  };
  const m = MSGS[langCode] || MSGS['en'];
  return JSON.stringify({
    chat_id: $('Router').item.json.userId,
    text: m.text
  });
})() }}

={{ (() => {
  const historyRaw = $('Get History').item.json.value || '[]';
  let history = [];
  try { history = JSON.parse(historyRaw); } catch(e) { history = []; }
  const userText = $('Telegram Trigger').item.json.message?.text || '';
  history.push({ role: 'user', content: userText });
  const nativeLang = $('Router').item.json.nativeLang || 'en';
  const targetLang = $('Router').item.json.targetLang || 'en';
  const LANG = { ru:'Russian',en:'English',es:'Spanish',zh:'Chinese',ar:'Arabic',
    pt:'Portuguese',fr:'French',de:'German',hi:'Hindi',ja:'Japanese',
    ko:'Korean',it:'Italian',tr:'Turkish',pl:'Polish',uk:'Ukrainian',
    nl:'Dutch',sv:'Swedish',vi:'Vietnamese',th:'Thai',id:'Indonesian' };
  const nativeName = LANG[nativeLang] || nativeLang;
  const targetName = LANG[targetLang] || targetLang;
  const system = `CRITICAL: ALL your text MUST be written in ${nativeName} ONLY. Never use any other language, no matter what language the student writes in.

You are assessing a student's ${targetName} level. Their native language is ${nativeName}.

Ask exactly 4 questions of increasing difficulty:
Q1: Ask their name and where they are from.
Q2: Ask them to describe their typical day.
Q3: Ask their opinion on climate change.
Q4: Ask what they would change about the education system and why.

Rules:
- Write EVERYTHING in ${nativeName}
- After each answer: brief warm reaction (1-2 sentences in ${nativeName}), then the next question in ${nativeName} labeled Question N/4
- After Q4 answer: 1-2 sentence assessment in ${nativeName}, then on a new line: LEVEL_RESULT: X (X = A1/A2/B1/B2/C1)
- No text after LEVEL_RESULT`;
  return JSON.stringify({ model: 'claude-haiku-4-5', max_tokens: 600, system, messages: history });
})() }}

