={{ (() => {
  const langCode = $('Router').item.json.langCode || 'en';
  const userId = $('Router').item.json.userId;
  const LANG_NAMES = {
    ru: 'Русский', en: 'English', es: 'Español', zh: '中文',
    ar: 'العربية', pt: 'Português', fr: 'Français', de: 'Deutsch',
    hi: 'हिन्दी', ja: '日本語', ko: '한국어', it: 'Italiano',
    tr: 'Türkçe', pl: 'Polski', uk: 'Українська', nl: 'Nederlands',
    sv: 'Svenska', vi: 'Tiếng Việt', th: 'ภาษาไทย', id: 'Bahasa Indonesia',
  };
  const CONFIRM_MSG = {
    ru: `🌍 Я вижу, что твой Telegram на *${LANG_NAMES[langCode] || langCode}*.
Продолжить на этом языке?`,
    en: `🌍 I see your Telegram is in *${LANG_NAMES[langCode] || langCode}*.
Continue in this language?`,
    es: `🌍 Veo que tu Telegram está en *${LANG_NAMES[langCode] || langCode}*.
¿Continuar en este idioma?`,
    fr: `🌍 Je vois que votre Telegram est en *${LANG_NAMES[langCode] || langCode}*.
Continuer dans cette langue ?`,
    de: `🌍 Ich sehe, dass dein Telegram auf *${LANG_NAMES[langCode] || langCode}* ist.
In dieser Sprache fortfahren?`,
    pt: `🌍 Vejo que seu Telegram está em *${LANG_NAMES[langCode] || langCode}*.
Continuar neste idioma?`,
    zh: `🌍 我看到你的 Telegram 使用 *${LANG_NAMES[langCode] || langCode}*。
继续使用这种语言吗？`,
    ar: `🌍 أرى أن تيليغرام على *${LANG_NAMES[langCode] || langCode}*.
هل تريد الاستمرار بهذه اللغة؟`,
    hi: `🌍 मैं देख सकता हूं कि आपका Telegram *${LANG_NAMES[langCode] || langCode}* में है।
क्या इसी भाषा में जारी रखें?`,
    ja: `🌍 あなたのTelegramは *${LANG_NAMES[langCode] || langCode}* になっています。
この言語で続けますか？`,
  };
  const CONTINUE_BTN = {
    ru: '✅ Продолжить', en: '✅ Continue', es: '✅ Continuar',
    fr: '✅ Continuer', de: '✅ Weiter', pt: '✅ Continuar',
    zh: '✅ 继续', ar: '✅ متابعة', hi: '✅ जारी रखें', ja: '✅ 続ける',
  };
  const OTHER_BTN = {
    ru: '🌐 Выбрать другой', en: '🌐 Choose another', es: '🌐 Elegir otro',
    fr: '🌐 Choisir autre', de: '🌐 Andere wählen', pt: '🌐 Escolher outro',
    zh: '🌐 选择其他', ar: '🌐 اختر آخر', hi: '🌐 दूसरा चुनें', ja: '🌐 他を選ぶ',
  };
  const msgText = CONFIRM_MSG[langCode] || CONFIRM_MSG['en'];
  const continueBtn = CONTINUE_BTN[langCode] || CONTINUE_BTN['en'];
  const otherBtn = OTHER_BTN[langCode] || OTHER_BTN['en'];
  return JSON.stringify({
    chat_id: userId,
    text: msgText,
    parse_mode: 'Markdown',
    reply_markup: {
      inline_keyboard: [[
        { text: continueBtn, callback_data: `confirm_lang_${langCode}` },
        { text: otherBtn, callback_data: 'choose_lang' }
      ]]
    }
  });
})() }}

