const raw = $('Generate Quiz').item.json.content[0].text;
const match = raw.match(/\[\s*\{[\s\S]*\}\s*\]/);
if (!match) throw new Error('Could not parse quiz JSON: ' + raw.slice(0, 200));
const questions = JSON.parse(match[0]);

// Enforce exactly 20 questions
if (questions.length < 20) {
  throw new Error('Claude returned only ' + questions.length + ' questions, expected 20');
}

const userId = $('Router').item.json.userId;
const level = $('Router').item.json.level || 'A1';
const nativeLang = $('Router').item.json.nativeLang || 'en';
const targetLang = $('Router').item.json.targetLang || 'en';

const quizState = {
  questions: questions.slice(0, 20),
  current: 0,
  answers: [],
  level, nativeLang, targetLang,
  startedAt: Date.now()
};
return [{ json: {
  userId,
  quizJson: JSON.stringify(quizState),
  quiz: quizState,
  nativeLang, level
} }];

