parameters.jsCode:
const transcript = $('Whisper STT').item.json.text || '';
const dictRaw = $('Get Dictation State').item.json.value || '{}';
let dictState = {};
try { dictState = JSON.parse(dictRaw); } catch(e) {}

const sentence = dictState.sentence || '';
const targetLang = dictState.targetLang || $('Router').item.json.targetLang || 'en';
const level = dictState.level || $('Router').item.json.level || 'A1';
const userId = $('Router').item.json.userId;
const nativeLang = $('Router').item.json.nativeLang || 'en';

// Normalize: lowercase, strip punctuation, collapse whitespace
function normalize(s) {
  return s.toLowerCase()
    .normalize('NFC')
    .replace(/[.,!?;:'"\-]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

const normTarget = normalize(sentence);
const normActual = normalize(transcript);

// Word-level accuracy
const targetWords = normTarget.split(' ').filter(Boolean);
const actualWords = normActual.split(' ').filter(Boolean);
const targetSet = new Set(targetWords);
const actualSet = new Set(actualWords);

let matched = 0;
targetWords.forEach(w => { if (actualSet.has(w)) matched++; });
const wordScore = targetWords.length > 0 ? Math.round((matched / targetWords.length) * 100) : 0;

// Find missed/wrong words
const missed = targetWords.filter(w => !actualSet.has(w));
const extra  = actualWords.filter(w => !targetSet.has(w));

const LANG = { en:'English',es:'Spanish',fr:'French',de:'German',it:'Italian',pt:'Portuguese',zh:'Chinese',ja:'Japanese',ko:'Korean',ar:'Arabic',hi:'Hindi',ru:'Russian',tr:'Turkish',pl:'Polish',uk:'Ukrainian',nl:'Dutch',sv:'Swedish',vi:'Vietnamese',th:'Thai',id:'Indonesian',tl:'Filipino',ms:'Malay',bn:'Bengali',ur:'Urdu',fa:'Persian',el:'Greek',cs:'Czech',sk:'Slovak',hu:'Hungarian',ro:'Romanian',bg:'Bulgarian',hr:'Croatian',sr:'Serbian',sl:'Slovenian',lt:'Lithuanian',lv:'Latvian',et:'Estonian',fi:'Finnish',da:'Danish',no:'Norwegian',he:'Hebrew',kk:'Kazakh',uz:'Uzbek',az:'Azerbaijani',ka:'Georgian',hy:'Armenian',mn:'Mongolian',si:'Sinhala',my:'Burmese',km:'Khmer',lo:'Lao',ne:'Nepali',pa:'Punjabi',gu:'Gujarati',mr:'Marathi',te:'Telugu',ta:'Tamil',kn:'Kannada',ml:'Malayalam',ps:'Pashto',sw:'Swahili',yo:'Yoruba',ig:'Igbo',zu:'Zulu',af:'Afrikaans',so:'Somali',am:'Amharic',lg:'Luganda',ln:'Lingala',mg:'Malagasy',ca:'Catalan',cy:'Welsh',ga:'Irish',mt:'Maltese',sq:'Albanian',mk:'Macedonian',be:'Belarusian',tg:'Tajik',tk:'Turkmen',ky:'Kyrgyz',eo:'Esperanto',la:'Latin' };
const nativeName = LANG[nativeLang] || nativeLang;
const targetName = LANG[targetLang] || targetLang;

const prompt =
  'The student did a ' + targetName + ' dictation exercise at level ' + level + '.\n\n' +
  'Target sentence: "' + sentence + '"\n' +
  'Student said (transcript): "' + transcript + '"\n' +
  'Word accuracy score: ' + wordScore + '/100\n' +
  (missed.length > 0 ? 'Missed/wrong words: ' + missed.join(', ') + '\n' : '') +
  (extra.length > 0  ? 'Extra words heard: ' + extra.join(', ') + '\n' : '') +
  '\nWrite a short feedback in ' + nativeName + ' ONLY. Format:\n' +
  '1. Score line: e.g. 🎯 ' + wordScore + '/100\n' +
  '2. One sentence: what was good or what was wrong (in ' + nativeName + ')\n' +
  '3. If score < 100: show correct sentence clearly\n' +
  '4. One pronunciation/accuracy tip in ' + nativeName + '\n' +
  'Max 200 characters total. Be encouraging.';

return [{ json: {
  userId, sentence, transcript, wordScore, missed, extra,
  targetLang, level, nativeLang,
  claudeBody: JSON.stringify({ model: 'claude-haiku-4-5', max_tokens: 400,
    messages: [{ role: 'user', content: prompt }] })
} }];

