const item = $input.first();
// Rename .oga to .ogg so Groq accepts it
if (item.binary && item.binary.data) {
  const bin = item.binary.data;
  if (bin.fileName) bin.fileName = bin.fileName.replace(/\.oga$/, '.ogg');
  if (bin.fileExtension) bin.fileExtension = bin.fileExtension.replace('oga', 'ogg');
  if (bin.mimeType === 'audio/ogg') bin.mimeType = 'audio/ogg';
}
return [item];

function sm2(easeFactor, interval, repetitions, quality) {
  let newInterval, newRepetitions;
  if (quality < 3) {
    newRepetitions = 0;
    newInterval = 1;
  } else {
    newRepetitions = repetitions + 1;
    if (repetitions === 0) { newInterval = 1; }
    else if (repetitions === 1) { newInterval = 6; }
    else { newInterval = Math.round(interval * easeFactor); }
  }
  const newEF = quality >= 3
    ? Math.max(1.3, easeFactor + 0.1 - (5 - quality) * (0.08 + (5 - quality) * 0.02))
    : easeFactor;
  return { interval: newInterval, easeFactor: newEF, repetitions: newRepetitions };
}

const cbData = $('Router').item.json.cbData;
const userId = $('Router').item.json.userId;
const raw = $('Load Flashcard State').item.json.value || '{}';
const state = JSON.parse(raw);

if (!state.cards || state.cards.length === 0) {
  return [{ json: { userId, stateJson: raw, state, isHint: false, isFinished: true, correctCount: 0, nativeLang: 'en', expired: true } }];
}

// Don't know (first time) → show hint, don't advance
if (cbData === 'daily_ans_dontknow' && !state.hintUsed) {
  state.hintUsed = true;
  return [{ json: {
    userId, stateJson: JSON.stringify(state), state,
    isHint: true, isFinished: false,
    nativeLang: state.nativeLang, level: state.level
  } }];
}

// Know or Don't know after hint → record result and advance
const card = state.cards[state.current];
const quality = (cbData === 'daily_ans_know' && !state.hintUsed) ? 5 : 1;
const sm2Result = sm2(card.easeFactor, card.interval, card.repetitions, quality);

state.results.push({
  vocabId: card.vocabId,
  word: card.word,
  quality,
  hintUsed: state.hintUsed,
  newInterval: sm2Result.interval,
  newEaseFactor: sm2Result.easeFactor,
  newRepetitions: sm2Result.repetitions
});

state.current += 1;
state.hintUsed = false;

const isFinished = state.current >= state.cards.length;
const correctCount = state.results.filter(r => r.quality >= 3).length;

return [{ json: {
  userId, stateJson: JSON.stringify(state), state,
  isHint: false, isFinished, correctCount,
  nativeLang: state.nativeLang, level: state.level,
  sessionId: state.sessionId
} }];

