={{ (() => {
  const results = $('Process Daily Answer').item.json.state.results;
  const userId = $('Router').item.json.userId;
  if (!results || results.length === 0) return 'SELECT 1';
  const vals = results.map(r =>
    '(' + r.vocabId + ',' + r.newEaseFactor.toFixed(4) + ',' + r.newInterval + ',' + r.newRepetitions + ')'
  ).join(',');
  return `UPDATE vocabulary AS v SET ease_factor = c.new_ef::float, interval = c.new_int::int, repetitions = c.new_rep::int, next_review = NOW() + (c.new_int || ' days')::interval FROM (VALUES ${vals}) AS c(vid, new_ef, new_int, new_rep) WHERE v.id = c.vid::int AND v.user_id = ${userId};`;
})() }}

