const ALLOWED_USERS = [185674280];
const tg = $('Telegram Trigger').item.json;
const msg = tg.message || {};
const cb = tg.callback_query || {};
const userId = msg.from?.id || cb.from?.id;

if (!ALLOWED_USERS.includes(userId)) {
  return [{ json: { userId, route: 'blocked' } }];
}

const text = (msg.text || '').trim();
const cbData = cb.data || '';
const session = $('Get Session').item.json.value || '';
const user = $('Get User').item.json;
const langCode = $('Prepare User').item.json.langCode || 'en';
const firstName = msg.from?.first_name || cb.from?.first_name || 'друг';
const level = user.level || 'A1';
const nativeLang = user.native_lang || langCode || 'en';
const targetLang = user.target_lang || 'en';
const totalXp = user.total_xp || 0;
const streak = user.streak || 0;
const hasProgress = (totalXp > 0 || streak > 0 || level !== 'A1') && user.native_lang != null;

let route = 'grammar';

if (text === '/start') {
  route = hasProgress ? 'start_existing' : 'start';
} else if (cbData === 'reset_yes') {
  route = 'start';
} else if (cbData === 'reset_no') {
  route = 'menu';
} else if (cbData === 'menu_progress' || text === '/progress') {
  route = 'progress';
} else if (cbData === 'menu_level' || text === '/level') {
  route = 'level_change';
} else if (cbData.startsWith('set_level_')) {
  route = 'set_level';
} else if (['menu_show'].includes(cbData) || text === '/menu') {
  route = 'menu';
} else if (cbData === 'menu_word') {
  route = 'menu_word_prompt';
} else if (cbData === 'menu_grammar') {
  route = 'menu_grammar_prompt';
} else if (cbData === 'menu_talk' || text.startsWith('/talk')) {
  route = 'conversation';
} else if (text === '/word' || text.startsWith('/word ')) {
  route = text === '/word' ? 'menu_word_prompt' : 'vocabulary';
} else if (text === '/help') {
  route = 'help';
} else if (text === '/quiz') {
  route = 'quiz';
} else if (cbData === 'quiz_new') {
  route = 'quiz';
} else if (cbData === 'quiz_continue') {
  route = 'quiz_continue';
} else if (cbData.startsWith('quiz_ans_')) {
  route = 'quiz_answer';
} else if (cbData.startsWith('confirm_lang_')) {
  route = 'confirm_lang';
} else if (cbData === 'choose_lang') {
  route = 'choose_lang';
} else if (cbData.startsWith('nl_')) {
  route = 'native_lang';
} else if (cbData.startsWith('tl_page_')) {
  route = 'target_lang_page';
} else if (cbData.startsWith('tl_')) {
  route = 'target_lang';
} else if (session === 'word_input') {
  route = 'vocabulary';
} else if (session === 'grammar_input') {
  route = 'grammar';
} else if (session === 'onboarding') {
  route = 'onboarding';
} else if (session === 'quiz') {
  route = 'quiz_session';
} else if (session === 'conversation') {
  route = 'conversation';
} else if (!text.includes(' ') && text.length > 0 && !text.startsWith('/')) {
  route = 'vocabulary';
}

const voiceFileId = msg.voice?.file_id || '';
return [{ json: { userId, firstName, level, totalXp, streak, nativeLang, targetLang, langCode, text, cbData, session, route, voiceFileId } }];

