={{ (() => {
  const userId = $('Router').item.json.userId;
  const cbData = $('Router').item.json.cbData || '';
  // nativeLang was just written to the DB this execution by Save Confirmed Lang (confirm_lang_XX)
  // or Save Native Lang (nl_XX). Router read the OLD DB value, so derive it from whichever
