// nativeLang was saved to DB this execution by Save Confirmed Lang / Save Native Lang.
// Router read the old DB value — so we derive it from cbData of those nodes.
// cbData at this point is 'tl_XX' (the target lang just chosen).
// We need native lang — it was set via confirm_lang_XX or nl_XX earlier.
// Since we can't reference those nodes conditionally, we store it in the
// Set Onboarding After Lang node's input via $('Router').item.json which
// still has the stale nativeLang. But the REAL value is in the userId's
// newly saved DB record. Workaround: read it from the Save Target Lang
// node's upstream cbData chain is complex. Instead, we pass it via a
// dedicated Redis key set by the lang-save step.
// 
// For now: nativeLang comes from $input.first().json which passes through
// from Set Onboarding After Lang (Redis set) — which got it from Save Target Lang
// → which got it from Router. Still stale.
//
// Real fix: the lang confirmation step must pass nativeLang forward explicitly.
// We read it from $('Router').item.json.cbData if it's tl_XX (target), that's wrong.
// Check if Save Confirmed Lang ran — its cbData was confirm_lang_XX.
// Check if Save Native Lang ran — its cbData was nl_XX.
// Use try/catch to pick whichever ran.

let nativeLang = 'en';
try {
  const cb = $('Save Confirmed Lang').item.json.cbData || '';
  if (cb.startsWith('confirm_lang_')) nativeLang = cb.replace('confirm_lang_', '');
} catch(e) {}
if (nativeLang === 'en') {
  try {
    const cb = $('Save Native Lang').item.json.cbData || '';
    if (cb.startsWith('nl_')) nativeLang = cb.replace('nl_', '');
  } catch(e) {}
}
if (nativeLang === 'en') {
  nativeLang = $('Router').item.json.nativeLang || 'en';
}

const targetLang = ($('Router').item.json.cbData || '').replace('tl_', '') || 'en';

const LANG = { en:'English',es:'Spanish',fr:'French',de:'German',it:'Italian',pt:'Portuguese',zh:'Chinese',ja:'Japanese',ko:'Korean',ar:'Arabic',hi:'Hindi',ru:'Russian',tr:'Turkish',pl:'Polish',uk:'Ukrainian',nl:'Dutch',sv:'Swedish',vi:'Vietnamese',th:'Thai',id:'Indonesian',tl:'Filipino',ms:'Malay',bn:'Bengali',ur:'Urdu',fa:'Persian',el:'Greek',cs:'Czech',sk:'Slovak',hu:'Hungarian',ro:'Romanian',bg:'Bulgarian',hr:'Croatian',sr:'Serbian',sl:'Slovenian',lt:'Lithuanian',lv:'Latvian',et:'Estonian',fi:'Finnish',da:'Danish',no:'Norwegian',he:'Hebrew',kk:'Kazakh',uz:'Uzbek',az:'Azerbaijani',ka:'Georgian',hy:'Armenian',mn:'Mongolian',si:'Sinhala',my:'Burmese',km:'Khmer',lo:'Lao',ne:'Nepali',pa:'Punjabi',gu:'Gujarati',mr:'Marathi',te:'Telugu',ta:'Tamil',kn:'Kannada',ml:'Malayalam',ps:'Pashto',sw:'Swahili',yo:'Yoruba',ig:'Igbo',zu:'Zulu',af:'Afrikaans',so:'Somali',am:'Amharic',lg:'Luganda',ln:'Lingala',mg:'Malagasy',ca:'Catalan',cy:'Welsh',ga:'Irish',mt:'Maltese',sq:'Albanian',mk:'Macedonian',be:'Belarusian',tg:'Tajik',tk:'Turkmen',ky:'Kyrgyz',eo:'Esperanto',la:'Latin' };

return [{ json: {
  ...$input.first().json,
  nativeLang,
  targetLang,
  nativeName: LANG[nativeLang] || nativeLang,
  targetName: LANG[targetLang] || targetLang,
} }];

