  const prompt = `Create exactly 20 multiple-choice quiz questions to test ${targetName} knowledge at level ${level}.
Mix: 10 grammar questions (verb forms, tenses, prepositions, articles) + 10 vocabulary questions (word meaning, synonyms, usage in context).
Questions should be in ${nativeName} (the student's native language) so they understand clearly.
Answer options should be in ${targetName}.

Respond ONLY with a JSON array, no other text:
[
  {
    "q": "question text in ${nativeName}",
    "options": ["option A in ${targetName}", "option B", "option C", "option D"],
    "correct": 0,
    "topic": "grammar|vocabulary",
    "explanation": "brief explanation in ${nativeName} of why the correct answer is right"
  },
  ...
]

Rules:
- correct is the INDEX (0-3) of the right answer
- Shuffle options so correct answer is NOT always first
- Questions must match level ${level} difficulty
- explanation will be shown to student if they answer wrong`;
  return JSON.stringify({ model: 'claude-haiku-4-5', max_tokens: 4000,
    messages: [{ role: 'user', content: prompt }] });
})() }}

